class GeneratedLocalizationsDelegate
    extends LocalizationsDelegate<WidgetsLocalizations> {
  const GeneratedLocalizationsDelegate();
  List<Locale> get supportedLocales {
    return const <Locale>[
      Locale("en", "US"),
      Locale("ar", "EG"),
      Locale("fr", "FR"),
      Locale("es", "ES"),
      Locale("de", "DE"),
      Locale("it", "IT"),
      Locale("ru", "RU"),
      Locale("ja", "JP"),
      Locale("ko", "KR"),
      Locale("pt", "PT"),
      Locale("hi", "IN"),
      Locale("tr", "TR"),
      Locale("ps", "AF"),
      Locale("ur", "PK")
    ];
  }

  LocaleResolutionCallback resolution({Locale? fallback}) {
    return (Locale? locale, Iterable<Locale> supported) {
      if (locale != null && isSupported(locale)) {
        return locale;
      }
      final Locale fallbackLocale = fallback ?? supported.first;
      return fallbackLocale;
    };
  }

  @override
  Future<WidgetsLocalizations> load(Locale locale) {
    I18n._locale ??= locale;
    I18n._shouldReload = false;
    final String lang = I18n._locale != null ? I18n._locale.toString() : "";
    final String languageCode =
        I18n._locale != null ? I18n._locale!.languageCode : "";
    if ("en_US" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_en_US());
    } else if ("ar_EG" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ar_EG());
    } else if ("fr_FR" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_fr_FR());
    } else if ("es_ES" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_es_ES());
    } else if ("de_DE" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_de_DE());
    } else if ("it_IT" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_it_IT());
    } else if ("ru_RU" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ru_RU());
    } else if ("ja_JP" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ja_JP());
    } else if ("ko_KR" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ko_KR());
    } else if ("pt_PT" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_pt_PT());
    } else if ("hi_IN" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_hi_IN());
    } else if ("tr_TR" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_tr_TR());
    } else if ("ps_AF" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ps_AF());
    } else if ("ur_PK" == lang) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ur_PK());
    } else if ("en" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_en_US());
    } else if ("ar" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ar_EG());
    } else if ("fr" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_fr_FR());
    } else if ("es" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_es_ES());
    } else if ("de" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_de_DE());
    } else if ("it" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_it_IT());
    } else if ("ru" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ru_RU());
    } else if ("ja" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ja_JP());
    } else if ("ko" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ko_KR());
    } else if ("pt" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_pt_PT());
    } else if ("hi" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_hi_IN());
    } else if ("tr" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_tr_TR());
    } else if ("ps" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ps_AF());
    } else if ("ur" == languageCode) {
      return SynchronousFuture<WidgetsLocalizations>(const _I18n_ur_PK());
    }

    return SynchronousFuture<WidgetsLocalizations>(const I18n());
  }

  @override
  bool isSupported(Locale locale) {
    for (var i = 0; i < supportedLocales.length; i++) {
      final l = supportedLocales[i];
      if (l.languageCode == locale.languageCode) {
        return true;
      }
    }
    return false;
  }

  @override
  bool shouldReload(GeneratedLocalizationsDelegate old) => I18n._shouldReload;
}
